import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly encoding user input using ESAPI HTML encoding
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedUserInput = codec.encode(userInput);

        // Including the properly encoded user input in the output HTML
        String output = "<div>" + encodedUserInput + "</div>";

        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
